import OpenAI from "openai";

export interface OpenAIEnv {
  OPENAI_API_KEY: string;
}

// The official `openai` SDK runs on Workers — it uses the global fetch, no
// Node built-ins. Create the client per request from the binding.
export function createOpenAI(env: OpenAIEnv) {
  return new OpenAI({ apiKey: env.OPENAI_API_KEY });
}
